# coding: utf-8

import os
import sys

import click

from rainbow_admin import __version__
from rainbow_admin.admin import RainbowAdmin
from rainbow_admin.errors import RainbowException

CONFIG_NAMES = ("app_id", "user_id", "secret_key", "sgn_method", "env", "timeout", "center")
DEBUG = os.environ.get("DEBUG") == "true"


def eprint(*args, **kwargs):
    print(*args, file=sys.stderr, **kwargs)


def err(msg):
    """红色打印，并退出"""
    click.secho(msg, err=True, fg="red")
    exit(1)


def info(msg):
    """绿色打印"""
    click.secho(msg, fg="green")


def get_admin(**kwargs):
    options = {}
    # from cli, overwrite previous
    options.update(kwargs)

    if not all([options.get(i) for i in ("app_id", "user_id", "secret_key")]):
        err(
            "don't find app_id,user_id and secret_key from command/env/config_file, "
            "please set 'RAINBOW_APP_ID','RAINBOW_USER_ID','RAINBOW_SECRET_KEY environment"
        )

    return RainbowAdmin(**{k: v for k, v in options.items() if k in CONFIG_NAMES})


class LazyAdmin(dict):
    """为了让 admin 懒加载。(否则 `rainbow-admin group` 可能会有未设置app_id等变量错误)"""

    def __getitem__(self, k):
        if k == "admin":
            return get_admin(**self)
        return super().__getitem__(k)


@click.group()
@click.option(
    "-a",
    "--app-id",
    type=str,
    default=None,
    help="rainbow config app id",
    show_envvar=True,
)
@click.option(
    "-u", "--user-id", type=str, default=None, help="user id for auth", show_envvar=True
)
@click.option(
    "-s",
    "--secret-key",
    type=str,
    default=None,
    help="signature secret key for auth",
    show_envvar=True,
)
@click.option(
    "-m",
    "--sgn-method",
    type=str,
    default="sha1",
    help="signature method for auth, use sha1/sha256, default sha256",
    show_envvar=True,
)
@click.option(
    "-e", "--env", type=str, default="Default", help="env of app", show_envvar=True
)
@click.option(
    "-t", "--timeout", type=int, default=5, help="request timeout", show_envvar=True
)
@click.option(
    "-c",
    "--center",
    type=str,
    default="http://api.rainbow_admin.woa.com:8080",
    help="address of service",
    show_envvar=True
)
@click.version_option(__version__)
@click.pass_context
def cli(ctx: click.Context, app_id, user_id, secret_key, sgn_method, env, timeout, center):
    # 初始化配置
    ctx.ensure_object(LazyAdmin)
    ctx.obj.update(
        dict(
            app_id=app_id,
            user_id=user_id,
            secret_key=secret_key,
            sgn_method=sgn_method,
            env=env,
            timeout=timeout,
            center=center,
        )
    )
    # ctx.obj["admin"] = get_admin(ctx)
    if ctx.invoked_subcommand is None:
        click.echo(ctx.get_help())


from .group import group_cli
from .config import config_cli
from .table import table_cli
from .release import release_cli
from .file import file_cli
from .env import env_cli

cli.add_command(group_cli)
cli.add_command(config_cli)
cli.add_command(table_cli)
cli.add_command(release_cli)
cli.add_command(file_cli)
cli.add_command(env_cli)


def main():
    try:
        cli(help_option_names=["-h", "--help"], auto_envvar_prefix="RAINBOW")
    except RainbowException as e:
        err(str(e))
    except Exception as e:
        import traceback
        import json

        if DEBUG:
            traceback.print_exc()
        eprint(
            json.dumps(
                {
                    "version": __version__,
                    "env": dict(os.environ),
                    "argv": sys.argv,
                    "err": str(e),
                    "stack": traceback.format_exc(),
                }
            )
        )
        # TODO: sentry?
        err("遇到错误，请将以上信息提交给rainbow团队.")


if __name__ == "__main__":
    main()
